INSERT INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
VALUES (509, 417, 4, 'Yoavkeidar9', 'Both are early-2000s thrillers with structural ambition that their screenplays cannot support — digital credibility failures in one, pacing insufficiency in the other — but their shared genre failure addresses different viewer expectations for the slow-burn and the tech thriller formats.', '');
